// The synthetic determinism check requires structural equality
    //   post1_self_ == post2_self_
    // for StrictlyOrderedMap<K>, whose private exec fields include
    // `keys: StrictlyOrderedVec<K>` (wrapping `v: Vec<K>`) and
    // `vals: Vec<ID>`. In this Verus version, `Vec<T>` has no
    // view-injectivity axiom (no `v1@ == v2@ ==> v1 == v2`) and no
    // `#[verifier::ext_equal]` is provided for it. The `valid()` and
    // `view()` predicates of `StrictlyOrderedMap` are `closed`, so from
    // outside the impl we cannot peek at the Vec fields either.
    //
    // Given those constraints, the abstract spec (`valid()`, `view()`,
    // and the gap forall) pins down only the abstract map view and the
    // gap behavior of post1_self_ and post2_self_ — they agree on those
    // (we assert it below) — but neither this proof nor any Verus
    // axiom available here can bridge that to struct equality without
    // an assume / external axiom (forbidden).
    if post1_self_.valid()
        && post1_self_@ == pre_self_@.insert(k, v)
        && (forall |lo: KeyIterator<K>, hi: KeyIterator<K>| post1_self_.gap(lo, hi) <==>
                        pre_self_.gap(lo, hi)
                    && !(lo.lt_spec(KeyIterator::new_spec(k))
                      && KeyIterator::new_spec(k).lt_spec(hi)))
        && post2_self_.valid()
        && post2_self_@ == pre_self_@.insert(k, v)
        && (forall |lo: KeyIterator<K>, hi: KeyIterator<K>| post2_self_.gap(lo, hi) <==>
                        pre_self_.gap(lo, hi)
                    && !(lo.lt_spec(KeyIterator::new_spec(k))
                      && KeyIterator::new_spec(k).lt_spec(hi)))
    {
        assert(post1_self_@ == post2_self_@);
        assert(forall |lo: KeyIterator<K>, hi: KeyIterator<K>|
            #[trigger] post1_self_.gap(lo, hi) <==> #[trigger] post2_self_.gap(lo, hi));
        assert(r1 == r2);
    }
